import{_ as a,o as n,c as i,a6 as e}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"Running und as a background service","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/software/run-und-as-service.md","filePath":"mainchain/software/run-und-as-service.md"}'),t={name:"mainchain/software/run-und-as-service.md"};function p(l,s,o,d,c,r){return n(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="running-und-as-a-background-service" tabindex="-1">Running <code>und</code> as a background service <a class="header-anchor" href="#running-und-as-a-background-service" aria-label="Permalink to &quot;Running \`und\` as a background service&quot;">​</a></h1><p>If you intend to run your node as a Validator on any of the public networks, then you will most likely need to permanently run <code>und</code> as a background service (as opposed to manually running <code>und start</code> and leaving a terminal window/SSH session open).</p><p>This can easily be done using <code>systemctl</code>, and setting up an appropriate service configuration.</p><p>The following is a generic *nix guide, and may need adapting for your particular distribution.</p><p>Any text editor can be used to create the service configuration file, for example <code>nano</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/systemd/system/und.service</span></span></code></pre></div><p>At a minimum, the service configuration should contain the following, replacing <code>USERNAME</code> and <code>FULL_PATH_TO</code> with your own values:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Unit]</span></span>
<span class="line"><span>Description=Unification Mainchain Validator Node</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Service]</span></span>
<span class="line"><span>User=USERNAME</span></span>
<span class="line"><span>Group=USERNAME</span></span>
<span class="line"><span>WorkingDirectory=/home/USERNAME</span></span>
<span class="line"><span>ExecStart=/usr/local/bin/und start --home /FULL_PATH_TO/.und_mainchain</span></span>
<span class="line"><span>Restart=on-failure</span></span>
<span class="line"><span>RestartSec=10s</span></span>
<span class="line"><span>LimitNOFILE=4096</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Install]</span></span>
<span class="line"><span>WantedBy=default.target</span></span></code></pre></div><p>It is entirely possible to create a more sophisticated service definition should you desire.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p><strong>Also see</strong>: <a href="/mainchain/migrations/cosmovisor.html">Using Cosmovisor with und: Quick Start</a> for details on running <code>und</code> with <code>cosmovisor</code>.</p></div><p>Next, inform <code>systemctl</code> of the new service:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> daemon-reload</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und</span></span></code></pre></div><p>The service can now be started:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und</span></span></code></pre></div><p>and stopped:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und</span></span></code></pre></div><p>in the background.</p><p>Finally, you can monitor the log output for the service by running:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span></code></pre></div>`,19)])])}const k=a(t,[["render",p]]);export{u as __pageData,k as default};
